    41→function fmtM(n: number) {
    42→  if (n >= 1_000_000) return `£${(n / 1_000_000).toFixed(2)}M`;
    43→  if (n >= 1_000)     return `£${(n / 1_000).toFixed(0)}K`;
    44→  return `£${n.toLocaleString()}`;
    45→}
